interface MarketItemCardProps {
    item: any;
    stock: number;
    inventoryCount: number;
    multiplier: number;
    isLocked: boolean;
    onAdd: (id: string, count: number) => void;
    onSetMultiplier: (id: string, val: number) => void;
}

export const MarketItemCard: React.FC<MarketItemCardProps> = ({ item, stock, inventoryCount, multiplier, isLocked, onAdd, onSetMultiplier }) => {
    const isSoldOut = stock <= 0;
    const meta = item.meta;

    // 1순위: ID 기반 파일명 우선 시도
    const [imgSrc, setImgSrc] = useState(getAssetUrl(`${item.id}.png`));

    // 이미지 로드 실패 시 폴백 처리
    const handleImgError = () => {
        if (meta.image && imgSrc !== getAssetUrl(meta.image)) {
            // 2순위: 메타데이터에 정의된 image 경로
            setImgSrc(getAssetUrl(meta.image));
        }
    };

    return (
        <div data-tutorial-id={item.id === 'furnace' ? 'FURNACE_ITEM' : undefined} className={`relative flex flex-col items-center p-2 rounded-2xl border transition-all h-[150px] md:h-[220px] justify-between overflow-hidden shadow-md ${isSoldOut ? 'bg-stone-900 border-stone-800 opacity-40 grayscale' : 'bg-stone-850 border-stone-800 hover:border-stone-600'}`}>
            {isLocked && <div className="absolute top-1 left-1 p-1 bg-red-900/80 rounded border border-red-500 z-20"><Lock className="w-2 h-2 text-white" /></div>}
            {inventoryCount > 0 && <div className="absolute top-1 left-1 px-1 py-0.5 rounded text-[6px] font-black uppercase border z-10 bg-slate-900/80 border-slate-600 text-slate-300 flex items-center gap-1"><Package className="w-2 h-2" />{inventoryCount}</div>}
            <div className={`absolute top-1 right-1 px-1 py-0.5 rounded text-[6px] font-black tracking-tighter border z-10 ${stock > 0 ? 'bg-emerald-950/60 text-emerald-400 border-emerald-500/40' : 'bg-red-950/60 text-red-500 border-red-500/40'}`}>{isSoldOut ? 'X' : stock}</div>

            <div className={`flex-1 w-full flex items-center justify-center transition-all mt-1 rounded-lg relative ${isSoldOut ? 'cursor-not-allowed' : 'cursor-pointer hover:bg-stone-800/50 active:scale-95'}`} onClick={() => !isSoldOut && onAdd(item.id, multiplier)}>
                <img src={imgSrc} onError={handleImgError} className="w-10 h-10 md:w-24 md:h-24 object-contain drop-shadow-md" />
                <RomanTierOverlay id={item.id} />
            </div>

            {!isSoldOut && meta.type !== 'KEY_ITEM' && meta.type !== 'SCROLL' && (
                <div className="flex gap-1 mb-1 scale-75 md:scale-100">
                    {[1, 5, 10].map(v => <button key={v} disabled={stock < v} onClick={() => onSetMultiplier(item.id, v)} className={`w-5 h-5 md:w-7 md:h-7 rounded-full border text-[7px] font-black transition-all ${multiplier === v ? 'bg-amber-600 border-amber-400 text-white' : 'bg-stone-900 border-stone-700 text-stone-500 hover:text-stone-300'}`}>{v}</button>)}
                </div>
            )}

            <div className="w-full text-center px-1"><h4 className={`text-[7px] md:text-[11px] font-black leading-none truncate ${meta.type === 'TECHNIQUE' ? 'text-amber-400' : 'text-stone-400'}`}>{meta.name}</h4></div>
            <div className={`w-full py-0.5 md:py-2 rounded-b-xl border-t flex flex-col items-center justify-center font-mono font-black ${isSoldOut ? 'bg-stone-900 border-stone-800 text-stone-700' : 'bg-stone-950 border-stone-800 text-amber-500 cursor-pointer hover:bg-amber-900/20 active:scale-95'}`} onClick={() => !isSoldOut && onAdd(item.id, multiplier)}>
                <div className="flex items-center gap-1 text-[7px] md:sm"><span>{meta.baseValue * multiplier}</span><Coins className="w-2 h-2 md:w-4 md:h-4" /></div>
            </div>
            {isSoldOut && <div className="absolute inset-0 z-30 flex items-center justify-center bg-black/60"><span className="bg-red-600 text-white text-[8px] font-black px-2 py-0.5 rounded rotate-12 uppercase">Sold Out</span></div>}
        </div>
    );
};

import React, { useState } from 'react';
import { ShoppingCart, X, Minus, Plus, ShoppingBag, Coins } from 'lucide-react';
import { materials } from '../../../../data/materials';
import { getAssetUrl } from '../../../../utils';

const RomanTierOverlay = ({ id }: { id: string }) => {
    if (id === 'scroll_t2') return <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><span className="text-amber-500 font-serif font-black text-[10px] drop-shadow-[0_1px_1px_rgba(0,0,0,0.8)] translate-y-0.5">II</span></div>;
    if (id === 'scroll_t3') return <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><span className="text-amber-500 font-serif font-black text-[10px] drop-shadow-[0_1px_1px_rgba(0,0,0,0.8)] translate-y-0.5">III</span></div>;
    if (id === 'scroll_t4') return <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><span className="text-amber-500 font-serif font-black text-[10px] drop-shadow-[0_1px_1px_rgba(0,0,0,0.8)] translate-y-0.5">IV</span></div>;
    return null;
};

const CartItemImage = ({ id, meta }: { id: string, meta: any }) => {
    const [imgSrc, setImgSrc] = useState(getAssetUrl(`${id}.png`));

    const handleImgError = () => {
        if (meta?.image && imgSrc !== getAssetUrl(meta.image)) {
            setImgSrc(getAssetUrl(meta.image));
        }
    };

    return (
        <div className="w-10 h-10 bg-stone-950 rounded-lg flex items-center justify-center shrink-0 shadow-inner relative">
            <img src={imgSrc} onError={handleImgError} className="w-8 h-8 object-contain" />
            <RomanTierOverlay id={id} />
        </div>
    );
};

interface ShoppingCartDrawerProps {
    isOpen: boolean;
    cart: Record<string, number>;
    total: number;
    gold: number;
    onRemove: (id: string) => void;
    onAdd: (id: string, count: number) => void;
    onDelete: (id: string) => void;
    onBuy: () => void;
}

export const ShoppingCartDrawer: React.FC<ShoppingCartDrawerProps> = ({ isOpen, cart, total, gold, onRemove, onAdd, onDelete, onBuy }) => {
    return (
        <div className={`h-full bg-stone-950/80 border-l border-stone-800 shadow-2xl flex flex-col transition-all duration-500 ${isOpen ? 'w-48 md:w-72' : 'w-0 overflow-hidden border-none'}`}>
            <div className="bg-stone-850 p-4 border-b border-stone-800 shrink-0"><h3 className="font-serif font-black text-stone-100 uppercase truncate">Cart Contents</h3></div>
            <div className="flex-1 overflow-y-auto p-3 space-y-3 custom-scrollbar">
                {Object.entries(cart).length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center opacity-10"><ShoppingCart className="w-10 h-10 mb-2"/><p className="text-[10px] font-black uppercase">Empty</p></div>
                ) : (
                    Object.entries(cart).map(([id, count]) => {
                        const meta = materials[id];
                        return (
                            <div key={id} className="bg-stone-900/60 p-2 rounded-xl border border-stone-800">
                                <div className="flex items-center gap-2 mb-2">
                                    <CartItemImage id={id} meta={meta} />
                                    <div className="flex-1 min-w-0"><div className="text-stone-100 font-bold text-[10px] truncate">{meta?.name || id}</div><div className="text-amber-600 font-mono text-[9px] font-black">{ (meta?.baseValue || 0) * count } G</div></div>
                                    <button onClick={() => onDelete(id)} className="text-stone-600 hover:text-red-500 transition-colors"><X className="w-3.5 h-3.5" /></button>
                                </div>
                                <div className="flex items-center justify-between bg-black/40 rounded p-1">
                                    <span className="text-[10px] font-mono font-black text-stone-200 ml-1">{count}</span>
                                    <div className="flex gap-1"><button onClick={() => onRemove(id)} className="w-6 h-6 bg-stone-800 rounded border border-stone-700 text-stone-300 active:scale-90"><Minus className="w-3.5 h-3.5 mx-auto" /></button><button onClick={() => onAdd(id, 1)} className="w-6 h-6 bg-stone-800 rounded border border-stone-700 text-stone-300 active:scale-90"><Plus className="w-3.5 h-3.5 mx-auto" /></button></div>
                                </div>
                            </div>
                        );
                    })
                )}
            </div>
            <div className="bg-stone-850 p-4 border-t border-stone-800 space-y-2 shrink-0">
                <div className="flex justify-between items-center text-[10px] text-stone-500 font-bold uppercase"><span>Total</span><span className={`text-lg font-mono font-black ${total > gold ? 'text-red-500' : 'text-emerald-400'}`}>{total}G</span></div>
                <button onClick={onBuy} disabled={total === 0 || total > gold} className={`w-full py-3 rounded-xl font-black text-[10px] transition-all flex items-center justify-center gap-2 shadow-xl ${total > gold ? 'bg-red-900/60 text-red-100 border border-red-500/50' : total === 0 ? 'bg-stone-800 text-stone-600 opacity-60' : 'bg-amber-600 hover:bg-amber-500 text-white'}`}><ShoppingBag className="w-4 h-4" /><span>{total > gold ? 'Shortage' : 'Buy Now'}</span></button>
            </div>
        </div>
    );
};

import React, { useState } from 'react';
import { useGame } from '../context/GameContext';
import { Package, Sword, Shield, Coins, Info, Zap, Wrench, ShieldAlert, AlertCircle, Brain, Lock, Unlock, Star, Sparkles } from 'lucide-react';
import { InventoryItem } from '../types/index';
import { getAssetUrl } from '../utils';

const RomanTierOverlay = ({ id }: { id: string }) => {
    if (id === 'scroll_t2') return <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><span className="text-amber-500 font-serif font-black text-xs md:text-xl drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)] translate-y-1">II</span></div>;
    if (id === 'scroll_t3') return <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><span className="text-amber-500 font-serif font-black text-xs md:text-xl drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)] translate-y-1">III</span></div>;
    if (id === 'scroll_t4') return <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><span className="text-amber-500 font-serif font-black text-xs md:text-xl drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)] translate-y-1">IV</span></div>;
    return null;
};

const AdaptiveInventoryImage = ({ item, className }: { item: InventoryItem, className?: string }) => {
    // 1순위: ID 기반 파일명 시도 (Equipment는 recipeId 우선)
    const baseId = (item.type === 'EQUIPMENT' && item.equipmentData?.recipeId) 
        ? item.equipmentData.recipeId 
        : item.id;

    const [imgSrc, setImgSrc] = useState(getAssetUrl(`${baseId}.png`));

    const handleImgError = () => {
        // 2순위: 아이템 메타데이터의 image 또는 equipmentData의 image 폴백
        const fallbackPath = item.image || item.equipmentData?.image;
        if (fallbackPath && imgSrc !== getAssetUrl(fallbackPath)) {
            setImgSrc(getAssetUrl(fallbackPath));
        }
    };

    return <img src={imgSrc} onError={handleImgError} className={className} />;
};

export const InventoryDisplay = () => {
    const { state, actions } = useGame();
    const [selectedItem, setSelectedItem] = useState<InventoryItem | null>(null);

    const handleSelect = (item: InventoryItem) => {
        setSelectedItem(item);
    };

    const handleQuickSell = () => {
        if (!selectedItem || selectedItem.isLocked) return;
        const sellPrice = Math.floor(selectedItem.baseValue * 0.5);
        if (sellPrice <= 0) return;
        actions.sellItem(selectedItem.id, 1, sellPrice, selectedItem.type === 'EQUIPMENT' ? selectedItem.id : undefined);
        if (selectedItem.quantity <= 1) setSelectedItem(null);
    };

    const handleConsume = () => {
        if (!selectedItem) return;
        actions.useItem(selectedItem.id);
        if (selectedItem.quantity <= 1) setSelectedItem(null);
    };

    const handleToggleLock = () => {
        if (!selectedItem) return;
        actions.toggleLockItem(selectedItem.id);
    };

    const getQualityLabel = (q: number): string => {
        if (q >= 110) return 'MASTERWORK';
        if (q >= 100) return 'PRISTINE';
        if (q >= 90) return 'SUPERIOR';
        if (q >= 80) return 'FINE';
        if (q >= 70) return 'STANDARD';
        if (q >= 60) return 'RUSTIC';
        return 'CRUDE';
    };

    const getRarityClasses = (rarity?: string) => {
        switch (rarity) {
            case 'Legendary': return 'text-amber-400 border-amber-500/50 bg-amber-950/40';
            case 'Epic': return 'text-purple-400 border-purple-500/50 bg-purple-950/40';
            case 'Rare': return 'text-blue-400 border-blue-500/50 bg-blue-950/40';
            case 'Uncommon': return 'text-emerald-400 border-emerald-500/50 bg-emerald-950/40';
            default: return 'text-stone-400 border-stone-700/50 bg-stone-900/40';
        }
    };

    const currentSelectedItem = state.inventory.find(i => i.id === selectedItem?.id) || null;
    if (selectedItem && !currentSelectedItem) setSelectedItem(null);

    const renderEquipmentStats = (item: InventoryItem) => {
        if (!item.equipmentData?.stats) return null;
        const s = item.equipmentData.stats;
        const isMagical = s.magicalAttack > s.physicalAttack || s.magicalDefense > s.physicalDefense;
        const atkLabel = isMagical ? "M.ATK" : "P.ATK";
        const defLabel = isMagical ? "M.DEF" : "P.DEF";
        const atkValue = isMagical ? s.magicalAttack : s.physicalAttack;
        const defValue = isMagical ? s.magicalDefense : s.physicalDefense;

        return (
            <div className="mb-4 space-y-1 shrink-0">
                <div className="grid grid-cols-2 gap-1.5">
                    <div className="flex justify-between bg-stone-900 p-1.5 rounded border border-stone-800 text-[9px] md:text-[10px]">
                        <span className="text-stone-500 uppercase flex items-center gap-1">
                            {isMagical ? <Zap className="w-2 h-2 text-blue-400" /> : <Sword className="w-2 h-2 text-stone-500" />}
                            {atkLabel}
                        </span>
                        <span className="font-mono text-stone-200 font-bold">{atkValue}</span>
                    </div>
                    <div className="flex justify-between bg-stone-900 p-1.5 rounded border border-stone-800 text-[9px] md:text-[10px]">
                        <span className="text-stone-500 uppercase flex items-center gap-1">
                            {isMagical ? <Brain className="w-2 h-2 text-purple-400" /> : <Shield className="w-2 h-2 text-stone-500" />}
                            {defLabel}
                        </span>
                        <span className="font-mono text-stone-200 font-bold">{defValue}</span>
                    </div>
                </div>
                {item.equipmentData.quality && (
                     <div className="flex justify-between bg-stone-900 p-1.5 rounded border border-stone-800 text-[9px] md:text-[10px]">
                        <span className="text-stone-500 uppercase flex items-center gap-1">
                            <Sparkles className="w-2 h-2 text-amber-500" /> Quality
                        </span>
                        <span className="font-black text-amber-500 uppercase tracking-tighter">{getQualityLabel(item.equipmentData.quality)}</span>
                    </div>
                )}
            </div>
        );
    };

    return (
        <div className="flex flex-row h-full w-full max-w-7xl mx-auto p-2 md:p-4 gap-2 md:gap-4 overflow-hidden">
            <div className="flex-[1.5] md:flex-[2.5] bg-slate-900 rounded-xl border border-slate-700 overflow-hidden flex flex-col min-w-0">
                <div className="bg-slate-800/50 p-2 md:p-3 border-b border-slate-700 flex items-center justify-between shrink-0">
                    <div className="flex items-center gap-2">
                        <Package className="w-3.5 h-3.5 md:w-4 md:h-4 text-amber-50" />
                        <h3 className="text-slate-200 text-xs md:text-sm uppercase tracking-wider font-bold">Storage</h3>
                    </div>
                    <span className="text-[10px] text-slate-500 font-mono">{state.inventory.length}</span>
                </div>
                <div className="p-2 overflow-y-auto flex-1 custom-scrollbar">
                    {state.inventory.length === 0 ? (
                        <div className="text-slate-500 text-center py-12 italic text-xs">Empty</div>
                    ) : (
                        <div className="grid grid-cols-2 xs:grid-cols-3 sm:grid-cols-4 lg:grid-cols-5 gap-2">
                            {state.inventory.map(item => {
                                const isSelected = currentSelectedItem?.id === item.id;
                                return (
                                    <button
                                        key={item.id} onClick={() => handleSelect(item)}
                                        className={`relative flex flex-col items-center p-2 rounded-lg border transition-all h-20 md:h-28 justify-between ${isSelected ? 'bg-amber-900/20 border-amber-500 shadow-md ring-1 ring-amber-500/50' : 'bg-slate-800/50 border-slate-700/50 hover:bg-slate-800 hover:border-slate-600'}`}
                                    >
                                        <div className="absolute top-1 right-1 bg-slate-950/80 px-1 rounded text-[8px] md:text-[10px] text-slate-400 font-mono flex items-center gap-1 z-20">
                                            {item.isLocked && <Lock className="w-2 h-2 md:w-2.5 md:h-2.5 text-amber-500" />}
                                            x{item.quantity}
                                        </div>
                                        <div className="flex-1 flex items-center justify-center relative">
                                             <AdaptiveInventoryImage item={item} className="w-6 h-6 md:w-10 md:h-10 object-contain" />
                                             <RomanTierOverlay id={item.id} />
                                        </div>
                                        <div className="text-[9px] md:text-xs text-center font-medium text-slate-300 w-full truncate">{item.name}</div>
                                    </button>
                                );
                            })}
                        </div>
                    )}
                </div>
            </div>

            <div className="flex-1 md:w-96 bg-black rounded-xl border border-stone-800 overflow-hidden flex flex-col min-w-0">
                <div className="bg-stone-900/50 p-2 md:p-3 border-b border-stone-800 flex items-center justify-between shrink-0">
                    <div className="flex items-center gap-2">
                        <Info className="w-3.5 h-3.5 md:w-4 md:h-4 text-stone-500" />
                        <h3 className="text-stone-400 text-[10px] md:text-xs uppercase tracking-wider font-bold">Details</h3>
                    </div>
                    {currentSelectedItem && (
                         <button 
                            onClick={() => actions.toggleLockItem(currentSelectedItem.id)}
                            className={`p-1.5 rounded-lg border transition-all ${currentSelectedItem.isLocked ? 'bg-amber-950/40 border-amber-600/50 text-amber-500' : 'bg-stone-900 border-stone-800 text-stone-600 hover:text-stone-300'}`}
                            title={currentSelectedItem.isLocked ? 'Unlock Item' : 'Lock Item'}
                         >
                            {currentSelectedItem.isLocked ? <Lock className="w-3.5 h-3.5" /> : <Unlock className="w-3.5 h-3.5" />}
                         </button>
                    )}
                </div>
                {currentSelectedItem ? (
                    <div className="flex-1 p-3 md:p-5 flex flex-col animate-in fade-in duration-300 overflow-y-auto custom-scrollbar">
                        <div className="flex flex-col items-center text-center mb-4 shrink-0">
                            <div className={`w-12 h-12 md:w-20 md:h-20 bg-stone-900 rounded-full border-2 flex items-center justify-center mb-2 shadow-lg relative ${currentSelectedItem.equipmentData ? getRarityClasses(currentSelectedItem.equipmentData.rarity) : 'border-stone-700'}`}>
                                <AdaptiveInventoryImage item={currentSelectedItem} className="w-8 h-8 md:w-12 md:h-12 object-contain" />
                                <RomanTierOverlay id={currentSelectedItem.id} />
                                {currentSelectedItem.isLocked && (
                                    <div className="absolute -top-1 -right-1 bg-amber-600 text-white p-1 rounded-full border border-stone-900 shadow-lg z-30">
                                        <Lock className="w-2.5 h-2.5 md:w-3.5 md:h-3.5" />
                                    </div>
                                )}
                            </div>
                            <h2 className="text-sm md:text-lg font-bold text-amber-500 font-serif leading-tight">{currentSelectedItem.name}</h2>
                            <div className="flex flex-wrap items-center justify-center gap-1.5 mt-1.5">
                                <span className="text-[7px] md:text-[9px] bg-stone-800 px-1.5 py-0.5 rounded text-stone-400 font-mono uppercase border border-white/5">{currentSelectedItem.type}</span>
                                {currentSelectedItem.equipmentData && (
                                    <span className={`text-[7px] md:text-[9px] px-1.5 py-0.5 rounded font-black uppercase border leading-none shadow-sm ${getRarityClasses(currentSelectedItem.equipmentData.rarity)}`}>
                                        {currentSelectedItem.equipmentData.rarity}
                                    </span>
                                )}
                            </div>
                        </div>

                        <p className="text-stone-400 text-[10px] md:text-xs italic leading-tight text-center mb-4 px-1">"{currentSelectedItem.description}"</p>

                        {renderEquipmentStats(currentSelectedItem)}

                        <div className="mt-auto space-y-2 pt-2">
                            {(currentSelectedItem.type === 'CONSUMABLE' || currentSelectedItem.type === 'SCROLL') && (
                                <button onClick={handleConsume} className="w-full py-2 bg-emerald-800 hover:bg-emerald-700 text-emerald-100 rounded text-[10px] md:text-sm font-bold transition-all">
                                    {currentSelectedItem.type === 'SCROLL' ? 'Study Scroll' : 'Use Item'}
                                </button>
                            )}
                            {currentSelectedItem.baseValue > 0 && currentSelectedItem.type !== 'KEY_ITEM' && (
                                <button 
                                    onClick={handleQuickSell} 
                                    disabled={currentSelectedItem.isLocked}
                                    className={`w-full py-2 rounded text-[10px] md:text-sm font-bold border transition-all ${currentSelectedItem.isLocked ? 'bg-stone-900 border-stone-800 text-stone-700 cursor-not-allowed' : 'bg-stone-800 hover:bg-red-900/30 text-stone-300 border-stone-700'}`}
                                >
                                    {currentSelectedItem.isLocked ? <span className="flex items-center justify-center gap-1"><Lock className="w-3 h-3" /> Item Locked</span> : `Sell (${Math.floor(currentSelectedItem.baseValue * 0.5)}G)`}
                                </button>
                            )}
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-stone-600 p-4 text-center">
                        <Package className="w-6 h-6 md:w-8 md:h-8 opacity-20 mb-2" />
                        <p className="text-[10px] md:text-xs">Select an item</p>
                    </div>
                )}
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { LayoutGrid, List, Lock, Unlock, Star, Sword, Shield, Coins, Package, Sparkles } from 'lucide-react';
import { InventoryItem } from '../types/inventory';
import { getAssetUrl } from '../utils';
import { useGame } from '../context/GameContext';

const RomanTierOverlay = ({ id, isList = false }: { id: string, isList?: boolean }) => {
    const sizeClasses = isList ? "text-[10px] md:text-lg" : "text-xs md:text-2xl";
    const translateClasses = isList ? "translate-y-0.5" : "translate-y-1 md:translate-y-2";

    if (id === 'scroll_t2') return <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><span className={`text-amber-500 font-serif font-black ${sizeClasses} drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)] ${translateClasses}`}>II</span></div>;
    if (id === 'scroll_t3') return <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><span className={`text-amber-500 font-serif font-black ${sizeClasses} drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)] ${translateClasses}`}>III</span></div>;
    if (id === 'scroll_t4') return <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><span className={`text-amber-500 font-serif font-black ${sizeClasses} drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)] ${translateClasses}`}>IV</span></div>;
    return null;
};

const AdaptiveItemImage = ({ item, className }: { item: InventoryItem, className?: string }) => {
    const baseId = (item.type === 'EQUIPMENT' && item.equipmentData?.recipeId) 
        ? item.equipmentData.recipeId 
        : item.id;

    const [imgSrc, setImgSrc] = useState(getAssetUrl(`${baseId}.png`));

    // 아이템이 변경되면 이미지 소스 초기화
    useEffect(() => {
        setImgSrc(getAssetUrl(`${baseId}.png`));
    }, [baseId]);

    const handleImgError = () => {
        const fallbackPath = item.image || item.equipmentData?.image;
        if (fallbackPath && imgSrc !== getAssetUrl(fallbackPath)) {
            setImgSrc(getAssetUrl(fallbackPath));
        }
    };

    return <img src={imgSrc} onError={handleImgError} className={className} />;
};

interface ItemSelectorListProps {
    items: InventoryItem[];
    onSelect: (item: InventoryItem) => void;
    onToggleLock: (itemId: string) => void;
    selectedItemId?: string | null;
    customerMarkup?: number;
    emptyMessage?: string;
}

export const ItemSelectorList: React.FC<ItemSelectorListProps> = ({ 
    items, 
    onSelect, 
    onToggleLock, 
    selectedItemId,
    customerMarkup = 1.0,
    emptyMessage = "No items available."
}) => {
    const { state, actions } = useGame();
    const viewMode = state.settings.inventoryViewMode || 'LIST';

    const setViewMode = (mode: 'GRID' | 'LIST') => {
        actions.updateSettings({ inventoryViewMode: mode });
    };

    const getQualityLabel = (q: number): string => {
        if (q >= 110) return 'Masterwork';
        if (q >= 100) return 'Pristine';
        if (q >= 90) return 'Superior';
        if (q >= 80) return 'Fine';
        if (q >= 70) return 'Standard';
        if (q >= 60) return 'Rustic';
        return 'Crude';
    };

    const getRarityColor = (rarity?: string) => {
        switch (rarity) {
            case 'Legendary': return 'text-amber-100 border-amber-400 bg-amber-600 shadow-[0_0_10px_rgba(245,158,11,0.4)]';
            case 'Epic': return 'text-purple-100 border-purple-400 bg-purple-600 shadow-[0_0_10px_rgba(168,85,247,0.4)]';
            case 'Rare': return 'text-blue-100 border-blue-400 bg-blue-600 shadow-[0_0_10px_rgba(59,130,246,0.4)]';
            case 'Uncommon': return 'text-emerald-100 border-emerald-400 bg-emerald-600 shadow-[0_0_10px_rgba(16,185,129,0.4)]';
            default: return 'text-stone-300 border-stone-600 bg-stone-700';
        }
    };

    if (items.length === 0) {
        return (
            <div className="flex-1 flex flex-col items-center justify-center text-stone-700 italic p-12 text-center bg-stone-950/40 rounded-2xl border border-stone-900 border-dashed m-4">
                <Package className="w-12 h-12 opacity-10 mb-2" />
                <p className="text-sm">{emptyMessage}</p>
            </div>
        );
    }

    return (
        <div className="flex-1 flex flex-col min-h-0 bg-stone-900/50">
            {/* View Mode Toggle */}
            <div className="flex justify-end p-2 px-4 gap-2 bg-stone-900 border-b border-white/5">
                <button 
                    onClick={() => setViewMode('GRID')}
                    className={`p-1.5 rounded-lg transition-all ${viewMode === 'GRID' ? 'bg-amber-600 text-white shadow-lg scale-110' : 'bg-stone-800 text-stone-500 hover:text-stone-300'}`}
                    title="Grid View"
                >
                    <LayoutGrid className="w-4 h-4" />
                </button>
                <button 
                    onClick={() => setViewMode('LIST')}
                    className={`p-1.5 rounded-lg transition-all ${viewMode === 'LIST' ? 'bg-amber-600 text-white shadow-lg scale-110' : 'bg-stone-800 text-stone-500 hover:text-stone-300'}`}
                    title="List View"
                >
                    <List className="w-4 h-4" />
                </button>
            </div>

            {/* Scrollable Container with Inset 3D Effect */}
            <div className={`flex-1 overflow-y-auto custom-scrollbar p-3 md:p-4 bg-stone-950 shadow-[inset_0_4px_20px_rgba(0,0,0,0.8)] min-h-0 ${viewMode === 'GRID' ? 'grid grid-cols-2 xs:grid-cols-3 sm:grid-cols-4 md:grid-cols-5 gap-3' : 'flex flex-col gap-2'}`}>
                {items.map(item => {
                    const isLocked = item.isLocked;
                    const isSelected = selectedItemId === item.id;
                    const isEquip = item.type === 'EQUIPMENT' && item.equipmentData;
                    const finalPrice = Math.ceil(item.baseValue * customerMarkup);

                    if (viewMode === 'GRID') {
                        const rarityClasses = getRarityColor(item.equipmentData?.rarity);
                        const stats = item.equipmentData?.stats;
                        const mainAtk = stats ? Math.max(stats.physicalAttack, stats.magicalAttack) : 0;
                        const mainDef = stats ? Math.max(stats.physicalDefense, stats.magicalDefense) : 0;
                        const qualityLabel = isEquip ? getQualityLabel(item.equipmentData!.quality) : '';

                        return (
                            <div key={item.id} className="relative group aspect-square">
                                <button
                                    onClick={() => !isLocked && onSelect(item)}
                                    disabled={isLocked}
                                    className={`w-full h-full rounded-xl border-2 transition-all flex flex-col items-center justify-center p-1 relative overflow-hidden shadow-2xl ${
                                        isSelected ? 'border-amber-400 bg-amber-900/20 ring-2 ring-amber-500/50' : 
                                        isLocked ? 'bg-stone-950 border-stone-900 opacity-40 grayscale' : 'bg-stone-800 border-stone-700 hover:border-amber-500 active:scale-95'
                                    }`}
                                >
                                    <div className="absolute inset-0 bg-gradient-to-br from-white/5 to-transparent pointer-events-none"></div>

                                    <div className="relative">
                                        <AdaptiveItemImage item={item} className="w-16 h-16 md:w-20 md:h-20 object-contain p-1 drop-shadow-[0_0_10px_rgba(0,0,0,0.5)]" />
                                        <RomanTierOverlay id={item.id} />
                                    </div>

                                    {/* Grid Top Info: Rarity Badge & Quantity */}
                                    <div className="absolute top-1.5 left-1.5 flex flex-col gap-1 pointer-events-none items-start max-w-[85%] z-20">
                                        {isEquip && (
                                            <div className={`px-1.5 py-0.5 rounded text-[7px] font-black uppercase border shadow-md leading-none ${rarityClasses}`}>
                                                {item.equipmentData!.rarity}
                                            </div>
                                        )}
                                        {item.quantity > 1 && (
                                            <div className="bg-stone-950/90 rounded px-1.5 py-0.5 text-[8px] font-mono font-black text-stone-400 border border-stone-800 shadow-md">
                                                x{item.quantity}
                                            </div>
                                        )}
                                    </div>

                                    {/* Quality Label Sparkle Overlay */}
                                    {isEquip && (
                                        <div className="absolute top-[60%] left-1/2 -translate-x-1/2 pointer-events-none z-20">
                                            <div className="bg-black/70 backdrop-blur-sm px-2 py-0.5 rounded-full flex items-center gap-1 border border-white/10 shadow-lg">
                                                <Sparkles className="w-2 h-2 text-amber-400" />
                                                <span className="text-[7px] font-black text-amber-200 uppercase whitespace-nowrap tracking-tight">{qualityLabel}</span>
                                            </div>
                                        </div>
                                    )}

                                    {/* Grid Bottom Info: Stats & Price */}
                                    <div className="absolute bottom-1 inset-x-1.5 flex justify-between items-end pointer-events-none z-20">
                                        {isEquip ? (
                                            <div className="flex flex-col gap-0.5">
                                                {mainAtk > 0 && (
                                                    <div className="bg-stone-900/90 px-1.5 rounded flex items-center gap-1 border border-orange-900/50 shadow-md">
                                                        <Sword className="w-2 h-2 text-orange-500" />
                                                        <span className="text-[8px] font-mono font-black text-stone-200">{mainAtk}</span>
                                                    </div>
                                                )}
                                                {mainDef > 0 && (
                                                    <div className="bg-stone-900/90 px-1.5 rounded flex items-center gap-1 border border-blue-900/50 shadow-md">
                                                        <Shield className="w-2 h-2 text-blue-400" />
                                                        <span className="text-[8px] font-mono font-black text-stone-200">{mainDef}</span>
                                                    </div>
                                                )}
                                            </div>
                                        ) : <div />}

                                        <div className="bg-stone-900/95 px-1.5 py-0.5 rounded-md flex items-center gap-0.5 border border-amber-900/40 shadow-xl">
                                            <span className="text-[9px] font-mono font-black text-amber-500">{finalPrice}</span>
                                            <Coins className="w-2.5 h-2.5 text-amber-600" />
                                        </div>
                                    </div>
                                </button>

                                {/* Floating Lock for Grid */}
                                <button 
                                    onClick={(e) => { e.stopPropagation(); onToggleLock(item.id); }}
                                    className={`absolute top-1.5 right-1.5 p-1.5 rounded-lg border transition-all z-30 shadow-xl ${isLocked ? 'bg-amber-600 border-amber-400 text-white' : 'bg-stone-900/80 border-stone-700 text-stone-500 opacity-0 group-hover:opacity-100 hover:text-stone-200 hover:bg-stone-800'}`}
                                >
                                    {isLocked ? <Lock className="w-3.5 h-3.5" /> : <Unlock className="w-3.5 h-3.5" />}
                                </button>
                            </div>
                        );
                    }

                    // --- LIST MODE ---
                    return (
                        <div key={item.id} className="relative group">
                            <button
                                onClick={() => !isLocked && onSelect(item)}
                                disabled={isLocked}
                                className={`w-full flex items-center gap-3 p-2 md:p-3 rounded-xl border-2 transition-all text-left shadow-lg relative overflow-hidden ${
                                    isSelected ? 'border-amber-400 bg-amber-900/20 ring-2 ring-amber-500/20' : 
                                    isLocked ? 'bg-stone-950 border-stone-900 opacity-50 grayscale cursor-not-allowed' : 'bg-stone-800 border-stone-700 hover:border-amber-500'
                                }`}
                            >
                                <div className="absolute inset-0 bg-gradient-to-r from-white/5 to-transparent pointer-events-none"></div>

                                <div className="w-10 h-10 md:w-16 md:h-16 bg-stone-950 rounded-lg border border-stone-800 flex items-center justify-center shrink-0 overflow-hidden relative shadow-[inset_0_2px_10px_rgba(0,0,0,0.6)]">
                                    <AdaptiveItemImage item={item} className="w-8 h-8 md:w-12 md:h-12 object-contain drop-shadow-md" />
                                    <RomanTierOverlay id={item.id} isList />
                                    {isLocked && <Lock className="absolute top-0.5 right-0.5 w-2.5 h-2.5 text-amber-500 z-30" />}
                                </div>

                                <div className="flex-1 min-w-0">
                                    <div className="flex items-center gap-2">
                                        <span className={`text-[11px] md:text-sm font-black truncate ${isLocked ? 'text-stone-500' : 'text-stone-100'}`}>{item.name}</span>
                                        {isEquip && (
                                            <div className={`px-1.5 py-0.5 rounded text-[7px] font-black uppercase border shadow-sm leading-none ${getRarityColor(item.equipmentData!.rarity)}`}>
                                                {item.equipmentData!.rarity}
                                            </div>
                                        )}
                                    </div>

                                    <div className="flex items-center gap-3 mt-1">
                                        {isEquip ? (
                                            <>
                                                <div className="flex items-center gap-1">
                                                    <Sparkles className="w-3 h-3 text-amber-500" />
                                                    <span className="text-[9px] font-black text-amber-500 uppercase italic tracking-tight">{getQualityLabel(item.equipmentData!.quality)} Grade</span>
                                                </div>
                                                <div className="flex items-center gap-2 text-[8px] font-mono font-bold text-stone-500 border-l border-stone-700 pl-2">
                                                    {(item.equipmentData!.stats.physicalAttack > 0 || item.equipmentData!.stats.magicalAttack > 0) && (
                                                        <span className="flex items-center gap-1"><Sword className="w-2.5 h-2.5" /> {item.equipmentData!.stats.physicalAttack || item.equipmentData!.stats.magicalAttack}</span>
                                                    )}
                                                    {(item.equipmentData!.stats.physicalDefense > 0 || item.equipmentData!.stats.magicalDefense > 0) && (
